INSERT INTO events (id, title, event_date_range, time, location, restaurant_name, tag, image_url, price, capacity, description, highlights_str, branch_id, event_dates_str, created_by, status, commission_rate, is_using_system_web, created_at) VALUES
(1, 'Lễ hội Tinh hoa Ẩm thực Đường phố', '28/06 - 30/06/2026', '16:00 - 22:00', 'Phố đi bộ Hồ Gươm, Hoàn Kiếm, Hà Nội', 'RMS Premium Catering', 'Festival', 'https://images.unsplash.com/photo-1555939594-58d7cb561ad1?auto=format&fit=crop&q=80&w=600', 'Miễn phí vào cửa', 'Không giới hạn', 'Lễ hội quy tụ hơn 50 gian hàng ẩm thực đường phố đặc sắc từ khắp các vùng miền Việt Nam và các nước châu Á. Du khách sẽ được thưởng thức các món ăn truyền thống được chế biến bởi các đầu bếp hàng đầu, tham gia các trò chơi dân gian ẩm thực và thưởng thức đêm nhạc Acoustic đường phố náo nhiệt.', 'Hơn 50 gian hàng ẩm thực đặc sắc;Biểu diễn nhạc sống Acoustic mỗi tối;Trải nghiệm tự tay làm bánh dân gian', '01-2thang9', '2026-06-28,2026-06-29,2026-06-30', 'admin@liteflow.com', 'APPROVED', 5.0, true, '2026-06-29 11:42:00'),
(2, 'Đêm nhạc Acoustic & Fine Wine Tasting', '04/07/2026', '19:30 - 22:30', 'Tầng 25, Skyline Lounge, Cầu Giấy, Hà Nội', 'Skyline Lounge', 'Fine Dining', 'https://images.unsplash.com/photo-1510812431401-41d2bd2722f3?auto=format&fit=crop&q=80&w=600', '850.000đ / khách', '40 khách', 'Hòa mình vào không gian lộng gió trên cao, thưởng thức ly rượu vang thượng hạng được tuyển chọn từ các vùng nho nổi tiếng nước Pháp và Ý, kết hợp hài hòa với thực đơn Canapes hải sản tinh tế. Đêm tiệc được đệm nhạc Acoustic guitar mộc mạc và du dương đón hoàng hôn thành phố.', 'Thử nếm 5 dòng rượu vang thượng hạng;Thực đơn Canapes hải sản cao cấp;View ngắm trọn hoàng hôn từ tầng cao', '11-NguyenHuuTho', '2026-07-04', 'admin@liteflow.com', 'APPROVED', 5.0, true, '2026-06-29 11:42:00'),
(3, 'Masterclass: Nghệ thuật làm Sushi truyền thống', '12/07/2026', '09:00 - 12:00', 'The Én Restaurant, Hoàn Kiếm, Hà Nội', 'The Én Restaurant', 'Workshop', 'https://images.unsplash.com/photo-1579871494447-9811cf80d66c?auto=format&fit=crop&q=80&w=600', '1.200.000đ / khách', '15 học viên', 'Khóa học thực hành trực tiếp cùng Bếp trưởng người Nhật với hơn 15 năm kinh nghiệm. Bạn sẽ được hướng dẫn từ khâu chọn cá hồi tươi sống, kỹ thuật nấu và trộn cơm giấm Shari chuẩn vị, đến nghệ thuật cuốn maki, nigiri đẹp mắt. Cuối buổi học là thời gian thưởng thức thành quả cùng trà xanh thượng hạng.', 'Hướng dẫn trực tiếp bởi bếp trưởng Nhật Bản;Nguyên liệu cá hồi/sò điệp nhập khẩu tươi ngon;Chứng nhận hoàn thành Masterclass từ The Én', '21-HaiPhong', '2026-07-12', 'admin@liteflow.com', 'APPROVED', 5.0, true, '2026-06-29 11:42:00'),
(4, 'Lễ hội Bia thủ công và Đồ nướng BBQ khổng lồ', '18/07 - 19/07/2026', '17:00 - 23:00', 'Vườn bia ngoài trời Cục Gạch Quán, Đống Đa, Hà Nội', 'Cục Gạch Quán', 'Festival', 'https://images.unsplash.com/photo-1544025162-d76694265947?auto=format&fit=crop&q=80&w=600', '150.000đ / vé (gồm 1 đồ uống)', '300 khách', 'Lễ hội thưởng thức hơn 20 loại bia thủ công đặc sắc từ các xưởng nấu bia danh tiếng Việt Nam kết hợp với đại tiệc nướng sườn tảng khổng lồ, bò Mỹ hun khói bằng gỗ sồi thơm nức. Không gian lễ hội trẻ trung sôi động với ban nhạc Rock nhẹ ngoài trời.', 'Hơn 20 vị bia thủ công độc đáo;BBQ hun khói khổng lồ chuẩn vị Mỹ;Đêm nhạc Rock & Gameshow vui nhộn', '01-2thang9', '2026-07-18,2026-07-19', 'admin@liteflow.com', 'APPROVED', 5.0, true, '2026-06-29 11:42:00'),
(5, 'Đại tiệc Truffle trắng nước Ý (Truffle Fine Dining)', '25/07/2026', '18:30 - 21:30', 'Phòng VIP Hoàng Gia, Tầm Vị Restaurant, Tây Hồ, Hà Nội', 'Tầm Vị Restaurant', 'Fine Dining', 'https://images.unsplash.com/photo-1540189549336-e6e99c3679fe?auto=format&fit=crop&q=80&w=600', '3.500.000đ / khách', '20 khách', 'Một hành trình ẩm thực xa hoa tôn vinh "kim cương trắng" của giới ẩm thực - Truffle Alba nhập khẩu trực tiếp từ Ý. Bếp trưởng thiết kế thực đơn 6 món Fine Dining kết hợp tài tình truffle bào mỏng trên nền mì tươi làm tay, súp kem măng tây và thăn bò Wagyu nướng sốt truffle.', 'Truffle trắng Alba tươi nhập khẩu trực tiếp;Thực đơn 6 món Fine Dining kết hợp rượu vang Ý;Không gian phòng VIP sang trọng, riêng tư', '11-NguyenHuuTho', '2026-07-25', 'admin@liteflow.com', 'APPROVED', 5.0, true, '2026-06-29 11:42:00'),
(6, 'Workshop: Nghệ thuật pha chế Cocktails cổ điển', '02/08/2026', '14:30 - 17:30', 'Skyline Lounge Bar, Cầu Giấy, Hà Nội', 'Skyline Lounge', 'Workshop', 'https://images.unsplash.com/photo-1514362545857-3bc16c4c7d1b?auto=format&fit=crop&q=80&w=600', '500.000đ / khách', '25 học viên', 'Tìm hiểu lịch sử và nghệ thuật đằng sau các ly cocktail cổ điển trường tồn với thời gian như Old Fashioned, Negroni, Whiskey Sour. Bạn được hướng dẫn kỹ năng lắc shaker, khuấy barspoon chuẩn xác và tự tay pha chế 3 ly cocktail của riêng mình dưới sự chỉ dẫn của các Bartender hàng đầu.', 'Học lý thuyết và thực hành pha chế 3 ly cocktail;Bộ dụng cụ pha chế chuyên nghiệp trang bị riêng;Quà tặng công thức pha chế độc quyền từ Bar trưởng', '21-HaiPhong', '2026-08-02', 'admin@liteflow.com', 'APPROVED', 5.0, true, '2026-06-29 11:42:00')
